        contactPage: { title: 'Kontaktieren Sie uns', subtitle: 'Wir sind hier, um zu helfen', resTitle: 'Reservierungen & Anfragen', resDesc: 'Unser Team von Reiseberatern steht Ihnen bei der Reiseplanung, Kabinenauswahl und Sonderwünschen zur Seite.', telUK: 'Telefon (UK)', telUS: 'Telefon (US)', email: 'E-Mail', officeTitle: 'Hauptsitz', pressTitle: 'Presseanfragen', pressDesc: 'Für Medienanfragen, Drehgenehmigungen und Bildlizenzen kontaktieren Sie bitte unser Pressebüro unter press@vsoe.com.' },
